(function(){
  var page=document.body?document.body.dataset.page:"";
  var data={
    "legal-dashboard":{note:"法务总览展示争议升级和证据包 proof，但 P0 不发起真实法律流程。",wallet:[["Legal reviewer wallet","0xLEG...64","ok"],["Role","Evidence Desk","ok"],["Legal authority","none in P0","bad"]],proof:[["Escalation root","0xlegq...01","ok"],["Dispute source","0xdsp...002","warn"],["Audit link","ready","ok"]],state:[["Escalated cases","1","warn"],["Evidence packs","3","ok"],["Real filings","0","ok"]],contract:[["Legal filing","disabled","bad"],["Fact mutation","disabled","bad"],["Read mode","enabled","ok"]]},
    "legal-case-review":{note:"合同核验页把条款、争议事实和责任方映射成 evidence map。",wallet:[["Legal reviewer","0xLEG...64","ok"],["Exporter wallet","0xEXP...21A","ok"],["Inspector owner","0xINS...44","warn"]],proof:[["Contract hash","0xcontract...52","ok"],["Inspection hash","0xgoods...fail","warn"],["Missing clause","minor defect","bad"]],state:[["Issue","inspection mismatch","warn"],["Original facts","unchanged","ok"],["Need materials","yes","warn"]],contract:[["Clause extraction","preview","warn"],["Legal opinion","none","bad"],["Audit note","ready","ok"]]},
    "legal-evidence-package":{note:"证据包页只生成 package index，不生成律师函或仲裁材料。",wallet:[["Legal reviewer","0xLEG...64","ok"],["Package owner","ChainTrace P0","warn"],["External counsel","not connected","bad"]],proof:[["Evidence pack","0xlegpack...001","ok"],["Timeline root","0xtimeline...leg","ok"],["Missing item root","0xmissing...02","warn"]],state:[["Facts included","yes","ok"],["Advice included","no","bad"],["Ready for review","draft","warn"]],contract:[["Court filing","none","bad"],["Arbitration filing","none","bad"],["Audit readable","yes","ok"]]},
    "legal-result":{note:"法务结果只记录证据包和下一步建议，不产生法律后果。",wallet:[["Legal reviewer","0xLEG...64","ok"],["Result owner","Evidence Desk","ok"],["Binding authority","none","bad"]],proof:[["Legal result hash","0xlegres...p0","ok"],["Evidence pack","0xlegpack...001","ok"],["Audit bundle","0xaudit...001","ok"]],state:[["Evidence pack","ready","ok"],["Legal filing","none","bad"],["Facts changed","no","ok"]],contract:[["Lawyer letter","none","bad"],["Binding decision","none","bad"],["Dispute link","ready","ok"]]}
  };
  var cfg=data[page];
  if(!cfg||document.getElementById("p0-legal-crypto-rail")||document.getElementById("p0-crypto-rail"))return;
  function st(){if(document.getElementById("p0-legal-crypto-rail-style"))return;var s=document.createElement("style");s.id="p0-legal-crypto-rail-style";s.textContent=".legal-crypto{border:1px solid rgba(52,211,153,.28);background:linear-gradient(135deg,rgba(52,211,153,.10),rgba(244,114,182,.08));border-radius:14px;box-shadow:var(--shadow);overflow:hidden}.legal-crypto-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:14px}.legal-crypto-card{border:1px solid rgba(159,178,201,.15);background:rgba(7,17,31,.30);border-radius:12px;padding:12px}.legal-crypto-card h3{margin:0 0 10px;font-size:15px}@media(max-width:1200px){.legal-crypto-grid{grid-template-columns:1fr}}";document.head.appendChild(s)}
  function badge(k){return k==="ok"?"ok":k==="warn"?"warn":"bad"}
  function rows(a){return a.map(function(r){return'<li><span><span class="small muted">'+r[0]+'</span><br><span class="strong">'+r[1]+'</span></span><span class="badge '+badge(r[2])+'">'+r[2]+'</span></li>'}).join("")}
  function run(){st();var sec=document.createElement("section");sec.id="p0-legal-crypto-rail";sec.className="section legal-crypto";sec.innerHTML='<div class="section-head"><div><h2>法务证据包加密证明轨迹</h2><p class="section-sub">'+cfg.note+'</p></div><span class="badge ok">evidence proof</span></div><div class="content legal-crypto-grid"><div class="legal-crypto-card"><h3>钱包 / 审阅方</h3><ul class="list">'+rows(cfg.wallet)+'</ul></div><div class="legal-crypto-card"><h3>证据证明</h3><ul class="list">'+rows(cfg.proof)+'</ul></div><div class="legal-crypto-card"><h3>案件状态</h3><ul class="list">'+rows(cfg.state)+'</ul></div><div class="legal-crypto-card"><h3>法律动作状态</h3><ul class="list">'+rows(cfg.contract)+'</ul></div></div>';var rail=document.getElementById("p0-legal-rail");if(rail&&rail.parentNode){rail.parentNode.insertBefore(sec,rail.nextSibling);return}var hero=document.querySelector(".main .hero");if(hero&&hero.parentNode)hero.parentNode.insertBefore(sec,hero.nextSibling);else document.querySelector(".main")?.prepend(sec)}
  if(document.readyState==="loading")document.addEventListener("DOMContentLoaded",run);else run();
})();